def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n < 4) return 0L

  val prefix = Array.fill(n + 1)(0L)
  for (i <- 0 until n) {
    prefix(i + 1) = prefix(i) + nums(i)
  }

  val left_incr = Array.fill(n)(1)
  val left_start = Array.fill(n)(0)
  for (i <- 1 until n) {
    if (nums(i) > nums(i - 1)) {
      left_incr(i) = left_incr(i - 1) + 1
      left_start(i) = left_start(i - 1)
    } else {
      left_start(i) = i
    }
  }

  val right_decr = Array.fill(n)(1)
  val right_end = Array.fill(n)(n - 1)
  for (i <- n - 2 downTo 0) {
    if (nums(i) > nums(i + 1)) {
      right_decr(i) = right_decr(i + 1) + 1
      right_end(i) = right_end(i + 1)
    } else {
      right_end(i) = i
    }
  }

  val right_incr = Array.fill(n)(1)
  val right_end2 = Array.fill(n)(n - 1)
  for (i <- n - 2 downTo 0) {
    if (nums(i) < nums(i + 1)) {
      right_incr(i) = right_incr(i + 1) + 1
      right_end2(i) = right_end2(i + 1)
    } else {
      right_end2(i) = i
    }
  }

  var maxSum = Long.MinValue
  for (p <- 0 until n) {
    if (left_incr(p) >= 2 && right_decr(p) >= 2) {
      val q = right_end(p)
      if (right_incr(q) >= 2) {
        val r = right_end2(q)
        val l = left_start(p)
        val currentSum = prefix(r + 1) - prefix(l)
        if (currentSum > maxSum) {
          maxSum = currentSum
        }
      }
    }
  }

  maxSum
}
